section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/qa-perf-run-verdict-template.json",
  "type": "object",
  "title": "QA Performance Run Verdict Template",
  "required": [
    "run_id",
    "verdict",
    "baseline_ref",
    "environment_fingerprint",
    "samples_per_endpoint",
    "metrics",
    "recommendation"
  ],
  "additionalProperties": false,
  "properties": {
    "run_id": {
      "type": "string",
      "minLength": 1,
      "description": "Run identifier."
    },
    "verdict": {
      "type": "string",
      "enum": [
        "PASS",
        "FAIL",
        "INCONCLUSIVE"
      ],
      "description": "Binary outcome."
    },
    "baseline_ref": {
      "type": "string",
      "minLength": 1,
      "description": "Baseline run id."
    },
    "environment_fingerprint": {
      "type": "string",
      "minLength": 1,
      "description": "Reproducible env id."
    },
    "samples_per_endpoint": {
      "type": "integer",
      "description": "Minimum sample count across endpoints."
    },
    "metrics": {
      "type": "array",
      "items": {
        "type": "object"
      },
      "description": "List of {endpoint, p50, p95, p99, error_rate, slo_target, pass}."
    },
    "recommendation": {
      "type": "string",
      "enum": [
        "release",
        "hold",
        "rollback"
      ],
      "description": "Release decision."
    }
  }
}
